import React from "react"

class Auth extends React.Component {
    constructor(props) {
        super(props)
        this.state = {
            name: "",
            password: ""
        }
    }
    render() {
        return (
            <div>
                <HeaderBeforeAuth />
                <form className="auth-form">
                    <input placeholder="Логин" onChange={(e) => this.setState({name: e.target.value})} />
                    <input placeholder="Пароль" onChange={(e) => this.setState({password: e.target.value})} />
                    <Link to="../">
                        <button onClick={() => this.props.onAdd({name: this.state.name, password: this.state.password})}>Войти</button>
                    </Link>
                    <h3></h3>
                </form>
            </div>
        )
    }
}

export default Auth
